head.script:
scwin.lineCd 	= $c.data.getParameter("lineCd") == null ? "" : $c.data.getParameter("lineCd");
scwin.lineNm 	= $c.data.getParameter("lineNm") == null ? "" : $c.data.getParameter("lineNm");
scwin.bookingNo = $c.data.getParameter("bookingNo") == null ? "" : $c.data.getParameter("bookingNo");

scwin.onpageload = function() {
	//scwin.f_FieldClear(); 임시

	//EDI오더현황조회 화면에서 넘어오는 경우 처리
	ed_cndBookingNo.setValue(scwin.bookingNo);

	//비활성화
	$c.gus.cfDisableObjects([tbl_infoArea]);
	$c.gus.cfEnableObjects([ed_sizeTypeInfo]);
    $c.gus.cfDisableObjects([btn_confirm, btn_linkC4, btn_linkC5, btn_linkC6, btn_linkC7]);

    scwin.initComp();
};

scwin.onUdcCompleted = function() {
	//EDI오더현황조회 화면에서 넘어오는 경우 처리
	ed_cndLineCd.setValue(scwin.lineCd);
	ed_cndLineNm.setValue(scwin.lineNm);

    //파라미터로 값이 있으면 바로 조회
	if (ed_cndLineCd.getValue().trim() != "" && ed_cndBookingNo.getValue().trim() != "") {
		scwin.f_Retrieve();
	}

    ed_cndLineCd.bind('onblur', function(e) {
        this._orgVal = this.getValue();
    })
};


scwin.initComp = function() {

    var objGrid = [gr_commInfo];

    // Grid ExcelFormat
    var dataTypeNum = ['number', 'float', 'bigDecimal'];
    var dataType, displayFormat;

    for (var i = 0 ; i < objGrid.length ; i++) {
        var column = objGrid[i].element.getElementsByTagName('w2:gBody')[0].getElementsByTagName('w2:column');

        for (var j = 0 ; j < column.length ; j++) {

            dataType    = column[j].getAttribute('dataType');

            if (dataTypeNum.includes(dataType)) {

                if (!column[j].getAttribute('excelCellType')) {
                    column[j].setAttribute('excelCellType', 'number');
                }

                if (!column[j].getAttribute('excelFormat')) {
                    displayFormat   = column[j].getAttribute('displayFormat');

                    if (displayFormat) {
                        var temp = displayFormat.split('.');

                        if (temp.length == 2) {
                            if ( temp[1].endsWith('0')) {
                                displayFormat = temp[0]  + '.' + '0'.padEnd(temp[1].length, '0');
                            } else {
                                displayFormat = temp[0]  + '.' + temp[1].substring(0,temp[1].length-1) + '0';
                            }
                        }
                        column[j].setAttribute('excelFormat', displayFormat);
                    }
                }
            }
        }
    }
}


//조회 callback
scwin.sbm_retrieve_submitdone = function (e) {

    // ds_cntrInfo Load
	var txt = "";
    if (ds_cntrInfo.getRowCount() != 0) {

		for (var i = 0; i < ds_cntrInfo.getRowCount; i++) { 

			txt += "SIZE/TYPE: " + (ds_cntrInfo.NameValue(i, "cntrSizCd")+" "+ds_cntrInfo.NameValue(i, "cntrTypCd") )
			   + ", 총 수량: " + ds_cntrInfo.NameValue(i, "qty") + "대"
			   + ", 반출수량: " + ds_cntrInfo.NameValue(i, "gateQty") + "대"
			   + ", 잔량: " + (parseInt(ds_cntrInfo.NameValue(i, "qty")) - parseInt(ds_cntrInfo.NameValue(i, "gateQty"))) + "대";
               + "\n";
		}
	}
    ed_sizeTypeInfo.setValue(txt);

    // ds_bookingInfo Load
    if (ds_bookingInfo.getRowCount() != 0) {

        ds_bookingInfo.setRowPosition(0);

        ds_bookingInfo.setCellData(0, "rcvHh", ds_bookingInfo.getCellData(0, "rcvHh").substring(0, 4));

        //Confrim 버튼 활성/비활성 (담당자, 확인일, 확인시간)
        if( ds_bookingInfo.getCellData(0, "confirmPicNm") == ""  && ds_bookingInfo.getCellData(0, "confirmDt") == ""  && ds_bookingInfo.getCellData(0, "confirmHh") == "" ){
            $c.gus.cfEnableBtnOnly([btn_confirm]); 
        } else {
            $c.gus.cfDisableBtnOnly([btn_confirm]);    
        }

        //컨테이너오더 Link 버튼 활성/비활성화
        var mcomOdrNo = ds_bookingInfo.getCellData(0, "mcomOdrNo"); //당사오더번호     

        if(!$c.gus.cfIsNull(mcomOdrNo)){
            var odrKndCd = mcomOdrNo.substring(1,3);

            $c.gus.cfDisableObjects([btn_linkC4, btn_linkC5, btn_linkC6, btn_linkC7]);

            if(odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR){
                $c.gus.cfEnableObjects([btn_linkC4]);

            } else if(odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR1) {
                $c.gus.cfEnableObjects([btn_linkC5]);

            } else if(odrKndCd== DsConstants.ODR_KND_CD_OFF_HIRE_ODR) {
                $c.gus.cfEnableObjects([btn_linkC6]);

            } else if(odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR) {
                $c.gus.cfEnableObjects([btn_linkC7]);
            }
        }else{  
            $c.gus.cfEnableObjects([btn_linkC4, btn_linkC5, btn_linkC6, btn_linkC7]);
        }   
    }else{
        $c.gus.cfAlertMsg(MSG_CM_ERR_003, ["조회결과"]);       
        scwin.f_FieldClear();
    }   

    totalRows.setValue(ds_commInfo.getAllJSON());

	totalRows.setValue(ds_commInfo.getRowCount());
};



//저장 callback
scwin.sbm_save_submitdone = function (e) {
    ed_cndLineCd.setValue(ed_lineCd.getValue());

    ed_cndLineNm.setValue(ed_lineNm.getValue());
    ed_cndBookingNo.setValue(ed_bookingNo.getValue());
    scwin.f_Retrieve();
};



//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function(type, disGubun, codeObj, nameObj, pClose, pAllSearch) {

    let codeVal = codeObj.getValue();
    let nameVal = nameObj.getValue();

    if (type == 'CODE') {
        nameObj.setValue('');

        if (codeVal == '') {
            codeObj.setValue('');
            return;
        }
    } else if (type == 'NAME'){
        codeObj.setValue('');
        if (nameVal == '') {
            nameObj.setValue('');
            return;
        }
    } 

   	if (type == 'CODE') {
        scwin.f_openCommonPopUp(disGubun, codeVal, '', pClose, pAllSearch);
    } else if (type == 'NAME') {
        scwin.f_openCommonPopUp(disGubun, '', nameVal, pClose, pAllSearch);
    } else if (type == 'SEARCH') {
        scwin.f_openCommonPopUp(disGubun, codeVal, nameVal, pClose, pAllSearch);
    }
}

//UDC
scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch, callback) {

    var pWhere  = '';
    scwin.isOpenPopup = true;

	switch (disGubun)
  	{
  		case "line":            // Line
		    pWhere = "";
		    udc_comCode.setSelectId('retrieveLineInfoList');
            udc_comCode.cfCommonPopUp(
                      function(ret) {
                            $c.gus.cfSetReturnValue(ret, ed_cndLineCd, ed_cndLineNm);
                      }
                    , pCode
                    , pName
                    , pClose
                    , null
                    , null
                    , null
                    , null
                    , pWhere
                    , null
                    , null
                    , null
                    , null
                    , null
                    , pAllSearch				// 전체검색허용여부	("F")
                    ,"Line,Line코드,Line명"    // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
			break;
        default:
            break;
    }
}

// Line
scwin.udc_comCode_onclickEvent = function (e) {
    scwin.f_chkOpenCommonPopUp('SEARCH', 'line', ed_cndLineCd, ed_cndLineNm, 'F', 'F');
};
scwin.udc_comCode_onblurCodeEvent = function (e) {

    var val = ed_cndLineCd.getValue();

    if (ed_cndLineCd._orgVal != val) {
        scwin.f_chkOpenCommonPopUp('CODE', 'line', ed_cndLineCd, ed_cndLineNm, 'T', 'T');
    }
};
scwin.udc_comCode_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp('NAME', 'line', ed_cndLineCd, ed_cndLineNm, 'T', 'T');
};



//조회 조건 초기화
scwin.f_FieldClear = function() {

    $c.gus.cfInitObjects(tbl_cndArea);
	$c.gus.cfDisableBtnOnly([btn_confirm]);
	$c.gus.cfDisableObjects([btn_linkC4, btn_linkC5, btn_linkC6, btn_linkC7]);

    ed_cndLineCd.focus();
};


//조회
scwin.f_Retrieve = async function() {
	if (await $c.gus.cfValidate([tbl_cndArea])) {
		$c.sbm.execute(sbm_retrieve);
	}
};

//확인
scwin.f_Confirm = function() {

    if(ds_bookingInfo.getRowCount() != 0 && ds_bookingInfo.getRowStatus(0) != 'R'){    
        $c.sbm.execute(sbm_save);
	}
};

//C4오더
scwin.btn_linkC4_onclick = function (e) {
    scwin.f_CntrOrderLink(DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR);
};

//C5오더
scwin.btn_linkC5_onclick = function (e) {
    scwin.f_CntrOrderLink(DsConstants.ODR_KND_CD_ON_HIRE_ODR);
};  

//C6오더
scwin.btn_linkC6_onclick = function (e) {
    scwin.f_CntrOrderLink(DsConstants.ODR_KND_CD_OFF_HIRE_ODR);
};


//C7오더
scwin.btn_linkC7_onclick = function (e) {
    scwin.f_CntrOrderLink(DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR);
};

scwin.f_CntrOrderLink = async function(odrKndCd) {

    var url     = "/ui/ds/sd/odrmgnt/odrreg/sd_402_01_11t.xml";
	var cond = {
          odrKndCd  :  odrKndCd //오더유형
		, lineCd    :  ds_bookingInfo.getCellData(0, "lineCd")
		, bookingNo :  ds_bookingInfo.getCellData(0, "bookingNo")
		, odrNo     :  ds_bookingInfo.getCellData(0, "mcomOdrNo")
		, pickupdt  :  ds_bookingInfo.getCellData(0, "pickupdt")
		, pickuphh  :  ds_bookingInfo.getCellData(0, "pickuphh")
		, linkPage  : "bookingNo"
		, type      : "create"
    };

    console.log(cond);

    // 열린탭 닫고 다시열기
    var tabObj  = $p.top().tac_layout;
    var tabInfo = tabObj.getTabInfo();

    tabObj.setEventPause(null, true);

    for (var i = 0 ; i < tabInfo.length ; i ++) {
        if (tabInfo[i].src == url) {
            await tabObj.deleteTab(i);
            break;
        }   
    }

    $c.win.openMenu(
		"컨테이너오더",
		"/ui/ds/sd/odrmgnt/odrreg/sd_402_01_11t.xml",
		"sd_402_01_11t.xml",
		cond
	);  

    tabObj.setEventPause(null, false);
};



//픽업지
scwin.displayFmRcvId = function(data) {
    return $c.gus.decode(data,"DBEXC051", "의왕CY", "DBEXC053", "부강CY", "DBEXC054", "익산CY", "DBEXC055", "구미CY", "DBEXC056", "광주CY", "");
};

//컨테이너소유구분
scwin.displayFmCntrPosnClsCd = function(data) {
    return $c.gus.decode(data,"0","무관","1","리즈","2","선사", "");
};



scwin.toUpperCase = function(e) {

    var obj     = window[e.target.id];

    if (obj.setValue) obj.setValue(e.target.value.toUpperCase());
}
